    ctx.fill();
    // Pants
    ctx.fillStyle = ped.pantsColor;
    ctx.fillRect(-2 * scale, -1 * scale, 4 * scale, 4 * scale);
    // Legs
    ctx.strokeStyle = ped.pantsColor;
